const { ticket_id, wer, was, severity, system_ip, session_id } = $('📥 Input').first().json;
if (!ticket_id) throw new Error('ticket_id erforderlich');
return { ticket_id, wer: wer || 'unknown', was: was || 'unknown', severity: severity || 'normal',
  system_ip: system_ip || null, session_id: session_id || require('crypto').randomUUID(),
  cycle: 1, context: [] };

const { ticket_id, wer, was, severity, system_ip, cycle, context, session_id } = $input.first().json;
const ctx = context.length > 0 ? `

Kontext aus Zyklus ${cycle-1}:
${context.join('
')}` : '';
return { prompt: `Incident Ticket #${ticket_id}: System=${wer}, Problem=${was}, Severity=${severity}, IP=${system_ip}${ctx}

Führe Root Cause Analysis durch. Antworte als JSON: {root_cause, affected_component, confidence(0-100), solution_approach, required_commands:[]}`,
  model: 'claude-sonnet-4-6', max_tokens: 1500, session_id };

const { ticket_id, cycle, session_id } = $('🔧 Init Incident').first().json;
const rca = $('🤖 SUB: Claude RCA').first().json;
const r = typeof rca.response === 'string' ? JSON.parse(rca.response) : rca.response || {};
const resolved = r.confidence >= 80;
return { exit_code: 'success', session_id, data: { ticket_id, cycle, resolved,
  root_cause: r.root_cause, confidence: r.confidence, solution: r.solution_approach },
  timestamp: new Date().toISOString() };
